const getTireGroups = (client: Client): TireGroup[] => {
    if (client.metadata) {
        try {
            const parsed = JSON.parse(client.metadata);
            if (parsed.groups && Array.isArray(parsed.groups)) return parsed.groups;
        } catch (e) {}
    }
    // Fallback parsing (legacy)
    const qrData = client['Заказ - QR'] || '';
    const jsonMatch = qrData.match(/\|\|JSON:(.*)$/);
    if (jsonMatch) {
         try {
            const parsed = JSON.parse(jsonMatch[1]);
            if (parsed.groups && Array.isArray(parsed.groups)) return parsed.groups;
        } catch (e) {}
    }

    // Basic reconstruction from fields if no JSON
    if (client['Бренд_Модель'] || client['Размер шин']) {
         const sizeStr = client['Размер шин'] || '';
         const diaMatch = sizeStr.match(/R(\d+)/i);
         const diameter = diaMatch ? diaMatch[1] : '';
         const sizeFullMatch = sizeStr.match(/(\d+)\/?(\d*)/);

         return [{
             id: 'legacy',
             brand: (client['Бренд_Модель'] || '').split(' ')[0] || 'Unknown',
             model: (client['Бренд_Модель'] || '').split(' ').slice(1).join(' ') || '',
             width: sizeFullMatch ? sizeFullMatch[1] : '',
             profile: sizeFullMatch ? sizeFullMatch[2] : '',
             diameter: diameter,
             count: Number(client['Кол-во шин']) || 4,
             season: client['Сезон'] || 'Лето',
             hasRims: client['Наличие дисков'] || 'Нет',
             pricePerMonth: Number(client['Цена за месяц']) || 0,
             dot: client['DOT-код'] || ''
         }];
    }
    return [];
};

