const MessageModal: React.FC<{
    client: Client;
    isOpen: boolean;
    onClose: () => void;
    templates: MessageTemplate[];
    showToast: (msg: string, type: 'success' | 'error') => void;
}> = ({ client, isOpen, onClose, templates, showToast }) => {
    const [mode, setMode] = useState<'select' | 'message'>('select');
    const [messageText, setMessageText] = useState('');
    const [selectedTemplateName, setSelectedTemplateName] = useState('');
    const [isSending, setIsSending] = useState(false);

    const handleGenerateReceipt = () => {
        const groups = getTireGroups(client);
        const formatCurrency = (val: number | undefined) => new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', minimumFractionDigits: 0 }).format(val || 0);

        let tiresText = '';
        if (groups.length > 0) {
            tiresText = groups.map((g, i) => {
                const dotInfo = g.dot ? `\nDOT: ${g.dot}` : '';
                return `<b>📦 Комплект ${i + 1}:</b>
${g.count}шт • ${g.brand} ${g.model}
Размер: <b>${g.width}/${g.profile} R${g.diameter}</b>
Сезон: ${g.season} | Диски: ${g.hasRims}${dotInfo}`;
            }).join('\n\n');
        } else {
            tiresText = (client['Заказ - QR'] || '').split('||JSON:')[0];
        }

        const receiptHtml = `
<b>📃 ДЕТАЛИ ЗАКАЗА (ДОГОВОР)</b>

👤 <b>Клиент:</b> ${client['Имя клиента']}
🚗 <b>Авто:</b> ${client['Номер Авто']}
📞 <b>Телефон:</b> ${client['Телефон']}

🔢 <b>Договор №:</b> <code>${client['Договор']}</code>
📅 <b>Срок хранения:</b> ${client['Срок']} мес.
(с ${formatDateForDisplay(client['Начало'])} по ${formatDateForDisplay(client['Окончание'])})

- - - - - - - - - - - - - -
${tiresText}
- - - - - - - - - - - - - -

💰 <b>Сумма заказа:</b> ${formatCurrency(client['Общая сумма'])}
(Тариф: ${formatCurrency(client['Цена за месяц'])}/мес)
${Number(client['Долг']) > 0 ? `❗️ <b>К оплате (Долг):</b> ${formatCurrency(client['Долг'])}` : ''}

📍 <b>Склад:</b> ${client['Склад хранения']}

<i>Приём и хранение осуществляется на условиях публичной оферты otelshin.ru/dogovor</i>
`.trim().replace(/\n/g, '<br/>');

        setMessageText(receiptHtml);
        setSelectedTemplateName('');
        setMode('message');
    };

    const applyTemplate = (template: MessageTemplate) => {
        let content = template['Содержимое (HTML)'];
        // Replace placeholders
        Object.keys(client).forEach(key => {
            const placeholder = new RegExp(`{{${key}}}`, 'g');
            let value = String(client[key as keyof Client] || '');
             if ((key === 'Окончание' || key === 'Напомнить' || key === 'Начало') && value) {
                const parsed = parseDate(value);
                if (parsed) value = parsed.toLocaleDateString('ru-RU');
            }
            if ((key === 'Долг' || key === 'Общая сумма') && typeof client[key] === 'number') {
                value = new Intl.NumberFormat('ru-RU').format(client[key]);
            }
            content = content.replace(placeholder, value);
        });
        setMessageText(content);
        setSelectedTemplateName(template['Название шаблона']);
        setMode('message');
    }

    const handleSend = async () => {
        if (!client['Chat ID']) {
            showToast('У клиента нет Chat ID', 'error');
            return;
        }
        setIsSending(true);
        try {
            const res = await api.sendMessage(client['Chat ID'], messageText);
            if (res.success) {
                showToast(res.message, 'success');
                onClose();
            } else {
                showToast(res.message, 'error');
            }
        } catch (e: any) {
             showToast(e.message, 'error');
        } finally {
            setIsSending(false);
        }
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={`Сообщение: ${client['Имя клиента']}`}>
            {mode === 'select' ? (
                <div className="space-y-3">
                    <p className="text-sm text-gray-500">Выберите шаблон или действие:</p>
                    <button onClick={handleGenerateReceipt} className="w-full p-3 text-left font-medium bg-indigo-50 text-indigo-700 hover:bg-indigo-100 rounded-lg transition-colors border border-indigo-200">
                        📄 Отправить договор / чек
                    </button>
                    <hr className="border-gray-100 dark:border-gray-700" />
                    <div className="grid gap-2 max-h-[300px] overflow-y-auto">
                        {templates.map(t => (
                            <button key={t['Название шаблона']} onClick={() => applyTemplate(t)} className="w-full p-3 text-left bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:border-primary-500 rounded-lg transition-all shadow-sm">
                                {t['Название шаблона']}
                            </button>
                        ))}
                    </div>
                    <button onClick={() => { setMessageText(''); setMode('message'); }} className="w-full p-2 text-center text-sm text-gray-500 hover:text-gray-700 underline">
                        Написать вручную
                    </button>
                </div>
            ) : (
                <div className="space-y-4">
                     <div className="flex justify-between items-center">
                         <button onClick={() => setMode('select')} className="text-sm text-blue-600 hover:underline">← Назад к шаблонам</button>
                         <span className="text-xs text-gray-400 font-mono">{client['Chat ID'] ? `ID: ${client['Chat ID']}` : 'Нет Chat ID'}</span>
                     </div>
                     <VisualEditor value={messageText} onChange={setMessageText} />
                     <div className="flex justify-end gap-2">
                         <Button variant="outline" onClick={onClose}>Отмена</Button>
                         <Button onClick={handleSend} disabled={isSending || !messageText}>
                             {isSending ? 'Отправка...' : 'Отправить'}
                         </Button>
                     </div>
                </div>
            )}
        </Modal>
    );
};

