interface ClientsViewProps {
  clients: Client[];
  headers: string[];
  templates: MessageTemplate[];
  refreshData: () => Promise<void>;
  savedViews: SavedView[];
  onSaveViews: (views: SavedView[]) => void;
}

const getTireGroups = (client: Client): TireGroup[] => {
    if (client.metadata) {
        try {
            const parsed = JSON.parse(client.metadata);
            if (parsed.groups && Array.isArray(parsed.groups)) return parsed.groups;
        } catch (e) {}
    }
    const qrData = client['Заказ - QR'] || '';
    const jsonMatch = qrData.match(/\|\|JSON:(.*)$/);
    if (jsonMatch) {
         try {
            const parsed = JSON.parse(jsonMatch[1]);
            if (parsed.groups) return parsed.groups;
        } catch (e) {}
    }
    return [{
        id: 'legacy',
        brand: (client['Бренд_Модель'] || '').split(' ')[0] || '',
        model: (client['Бренд_Модель'] || '').split(' ').slice(1).join(' ') || '',
        width: '',
        profile: '',
        diameter: (client['Размер шин'] || '').match(/R(\d+)/i)?.[1] || '',
        count: Number(client['Кол-во шин']) || 4,
        season: client['Сезон'] || 'Лето',
        hasRims: client['Наличие дисков'] || 'Нет',
        pricePerMonth: Number(client['Цена за месяц']) || DEFAULT_PRICE,
        dot: client['DOT-код'] || ''
    }];
};

